#define DEMO_UART UART4

#define DEMO_UART_CLK_FREQ BOARD_DEBUG_UART_CLK_FREQ

#define ECHO_BUFFER_LENGTH 8

DEMO_UART：定义使用的 UART 接口（此处为 UART4）。

DEMO_UART_CLK_FREQ：定义 UART 时钟频率（使用之前定义的波特率）。

ECHO_BUFFER_LENGTH：定义缓冲区长度为 8，用于接收和发送数据。

void UART_UserCallback(UART_Type *base, uart_handle_t *handle, status_t status, void *userData);

声明了一个回调函数 UART_UserCallback，用于处理 UART 中断事件。

uart_handle_t g_uartHandle;

uint8_t g_tipString[] =

"Uart interrupt transfer example\r\nBoard receives 8 characters then sends them out\r\nNow please input:\r\n";

uint8_t g_txBuffer[ECHO_BUFFER_LENGTH] = {0};

uint8_t g_rxBuffer[ECHO_BUFFER_LENGTH] = {0};

volatile bool rxBufferEmpty = true;

volatile bool txBufferFull = false;

volatile bool txOnGoing = false;

volatile bool rxOnGoing = false;

g_uartHandle：UART句柄，用于 UART 操作。

g_tipString：提示用户的字符串，告知输入 8 个字符。

g_txBuffer 和 g_rxBuffer：用于存储发送和接收的数据缓冲区（大小为 8）。

rxBufferEmpty、txBufferFull、txOnGoing、rxOnGoing：这些是标志变量，用于指示 UART 接收和发送状态。

/* UART user callback */

void UART_UserCallback(UART_Type *base, uart_handle_t *handle, status_t status, void *userData)

{

userData = userData; // 此行未使用，可能是占位符

if (kStatus_UART_TxIdle == status)

{

txBufferFull = false;

txOnGoing = false;

}

if (kStatus_UART_RxIdle == status)

{

rxBufferEmpty = false;

rxOnGoing = false;

}

}

此函数在 UART 发送和接收完成时被调用。

如果状态为 kStatus_UART_TxIdle，说明发送完成，将 txBufferFull 和 txOnGoing 标志设置为 false。

如果状态为 kStatus_UART_RxIdle，说明接收完成，将 rxBufferEmpty 和 rxOnGoing 标志设置为 false。

