/*调试串口为 UART2，波特率为 115200*/ 
console=ttymxc1,115200 
/*dtb 文件读取到 DDR 的地址为 0x43000000*/ 
fdt_addr=0x43000000 
/*dtb 文件名为 tlimx8-evm.dtb*/ 
fdtfile=tlimx8mp-evm.dtb 
/*内核镜像名称*/ 
image=Image 
/*环境变量 jh_clk 为空*/ 
jh_clk= 
/*内核镜像读取至 DDR 的地址为 0x40480000*/ 
loadaddr=0x40400000 
/*loadbootscript 命令：读取系统启动卡中的 U-Boot 脚本文件到加载地址*/ 
loadbootscript=fatload mmc ${mmcdev}:${mmcpart} ${loadaddr} ${script}; 
/*loadfdt 命令：读取 fdt 文件到 fdt 加载地址*/ 
loadfdt=fatload mmc ${mmcdev}:${mmcpart} ${fdt_addr} ${fdt_file} 
/*loadimage 命令：读取 image 镜像到内核镜像加载地址*/ 
loadimage=fatload mmc ${mmcdev}:${mmcpart} ${loadaddr} ${image} 
/*mmcboot 启动时先设置环境变量 bootargs*/ 
mmcargs=setenv bootargs ${jh_clk} console=${console} root=${mmcroot} 
/*系统启动卡启动会首先打印语句"Booting from mmc ... "，若环境变量 boot_fit 为 yes 或者 fit（默认
为 no），则直接从加载地址启动，否则先读设备树 fdt，再从加载地址启动*/ 
mmcboot=echo Booting from mmc ...; run mmcargs; if test ${boot_fit} = yes || test ${boot_fit} = 
try; then bootm ${loadaddr}; else if run loadfdt; then booti ${loadaddr} - ${fdt_addr}; else echo 
WARN: Cannot load the DT; fi; fi;
